sql:
SELECT fatalities
FROM accidents
WHERE accident_id = 0;

SELECT summary 
FROM accidents
WHERE event_type_id = 0;

SELECT AVG(fatalities) AS overall_average_fatalities
FROM accidents
WHERE investigation_status = 'Completed';

